#include "jni.h"#include "android/log.h"#include <cstdio>#include <unistd.h>#include <asm-generic/fcntl.h>#include "sys/epoll.h"#include "sys/prctl.h"#include "thread"#include "util.h"#include "map"#include "ctime"#define LOGI(...) __android_log_print(ANDROID_LOG_INFO, "KsuToast", __VA_ARGS__)#define LOGE(...) __android_log_print(ANDROID_LOG_ERROR, "KsuToast", __VA_ARGS__)#define TASK_COMM_LEN  16#define KSU_EVENT_TYPE_DROPPED 0xFFFFu#define KSU_SULOG_EVENT_ROOT_EXECVE 1u#define KSU_SULOG_EVENT_SUCOMPAT 2ustatic JavaVM *jvm = nullptr;static jclass globalEntryClass = nullptr;static jmethodID onNewSuEventJavaMethod = nullptr;static std::map<uint32_t, time_t> toastedUidMap;static bool autoDeleteLog = false;struct __attribute__((packed)) EventRecordHeader {    uint16_t record_type;    uint16_t flags;    uint32_t payload_len;    uint64_t seq;    uint64_t ts_ns;};struct __attribute__((packed)) SulogEventHeader {    uint16_t version;    uint16_t event_type;    int32_t retval;    uint32_t pid, tgid, ppid, uid, euid;    char comm[TASK_COMM_LEN];    uint32_t filename_len, argv_len;};void processSuEvent(JNIEnv *threadJniEnv, uint32_t uid) {    time_t currentTime = time(nullptr);    //按 uid 限速，同一 uid 3 秒内只弹一次    auto findResult = toastedUidMap.find(uid);    if (findResult != toastedUidMap.end()) {        if (currentTime - findResult->second <= 3) return;    }    if (toastedUidMap.size() > 16) {        toastedUidMap.erase(toastedUidMap.begin());    }    toastedUidMap[uid] = currentTime;    threadJniEnv->CallStaticVoidMethod(globalEntryClass, onNewSuEventJavaMethod, (jint)uid);}void pollingLogEvent(int suLogFd) {    JNIEnv *localJniEnv;    jvm->AttachCurrentThread(&localJniEnv, nullptr);    //Android特色对线程提权    setresuid(0, 0, 0);    {        int fl = fcntl(suLogFd, F_GETFL);        fcntl(suLogFd, F_SETFL, fl | O_NONBLOCK);    }    int epfd = epoll_create1(EPOLL_CLOEXEC);    epoll_event ev{EPOLLIN | EPOLLERR | EPOLLHUP, {.fd = suLogFd}};    epoll_ctl(epfd, EPOLL_CTL_ADD, suLogFd, &ev);    static uint8_t buf[8192];    epoll_event events[4];    while (true) {        int ready = epoll_wait(epfd, events, 4, -1);        if (ready < 0) {            if (errno == EINTR) continue;            break;        }        for (int i = 0; i < ready; i++) {            uint32_t mask = events[i].events;            if (mask & EPOLLIN) {                for (;;) {                    ssize_t n = read(suLogFd, buf, sizeof(buf));                    if (n <= 0) {                        if (n < 0 && (errno == EINTR)) continue;                        if (n < 0 && (errno == EAGAIN || errno == EWOULDBLOCK)) break;                        goto done;                    }                    for (size_t off = 0; off + sizeof(EventRecordHeader) <= (size_t) n;) {                        auto *rec = reinterpret_cast<EventRecordHeader *>(buf + off);                        size_t frame = sizeof(EventRecordHeader) + rec->payload_len;                        if (off + frame > (size_t) n) break;                        if (rec->record_type != KSU_EVENT_TYPE_DROPPED) {                            auto *hdr = reinterpret_cast<SulogEventHeader *>(buf + off +                                                                             sizeof(EventRecordHeader));                            if (rec->payload_len >= sizeof(SulogEventHeader) && hdr->uid != 0 &&                                hdr->retval == 0) {                                //ROOT_EXECVE 和 SUCOMPAT 统一处理，uid 会在 Java 层过滤                                if (hdr->event_type == KSU_SULOG_EVENT_ROOT_EXECVE ||                                    hdr->event_type == KSU_SULOG_EVENT_SUCOMPAT) {                                    processSuEvent(localJniEnv, hdr->uid);                                }                            }                        }                        off += frame;                    }                }            }            if (mask & (EPOLLERR | EPOLLHUP)) goto done;        }    }    done:    close(epfd);    close(suLogFd);    jmethodID modifyModuleDescriptionMethod = localJniEnv->GetStaticMethodID(globalEntryClass,                                                                             "onFatalException",                                                                             "(Ljava/lang/String;)V");    jstring description = localJniEnv->NewStringUTF("Error on working,Exited");    localJniEnv->CallStaticVoidMethod(globalEntryClass, modifyModuleDescriptionMethod, description);    localJniEnv->DeleteLocalRef(description);    jvm->DetachCurrentThread();    LOGE("pollingLogEvent exited");}bool handleSuLog() {    int driverFd = getKernelSuDriver();    if (driverFd < 0) {        LOGE("Failed to open kernel su driver");        return false;    }    int suLogFd = getSuLogFd(driverFd);    close(driverFd);    if (suLogFd < 0) {        LOGE("Failed to get Su log fd");        return false;    }    std::thread pollingThread(pollingLogEvent, suLogFd);    pollingThread.detach();    if (autoDeleteLog) deleteSuLogFile();    return true;}JNIEXPORT jint JNICALL JNI_OnLoad(JavaVM *vm, void *reserved) {    JNIEnv *jniEnv;    jvm = vm;    vm->GetEnv(reinterpret_cast<void **>(&jniEnv), JNI_VERSION_1_6);    prctl(PR_SET_KEEPCAPS, 1, 0, 0, 0);    vm->GetEnv(reinterpret_cast<void **>(&jniEnv), JNI_VERSION_1_6);    jclass entryClass = jniEnv->FindClass("com/suisho/kernelsugranttoast/Entry");    globalEntryClass = reinterpret_cast<jclass>(jniEnv->NewGlobalRef(entryClass));    onNewSuEventJavaMethod = jniEnv->GetStaticMethodID(globalEntryClass, "jniOnNewSuEvent",                                                       "(I)V");    jniEnv->DeleteLocalRef(entryClass);    return JNI_VERSION_1_6;}extern "C"JNIEXPORT jboolean JNICALLJava_com_suisho_kernelsugranttoast_Entry_jniInit(JNIEnv *env, jclass clazz, jboolean deleteLog) {    autoDeleteLog = deleteLog;    if (!handleSuLog()) return false;    LOGI("JNI init successful");    return true;}extern "C"JNIEXPORT void JNICALLJava_com_suisho_kernelsugranttoast_Entry_jniSetUid(JNIEnv *env, jclass clazz, jint uid) {    setresuid(uid, uid, 0);}
